function solve(m, n, waitCost) {
    const dp = new Array(m).fill().map(() => new Array(n).fill().map(() => ({ odd: Infinity, even: Infinity })));
    dp[0][0].odd = (0 + 1) * (0 + 1); // Initial entry cost at step 1 (odd)

    const directions = [[1, 0], [0, 1]]; // Down and Right

    for (let step = 1; step <= 2 * m * n; step++) {
        const isOddStep = step % 2 === 1;
        const newDp = new Array(m).fill().map(() => new Array(n).fill().map(() => ({ odd: Infinity, even: Infinity })));

        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (isOddStep) {
                    // Can move from adjacent cells (previous step was even, waited)
                    for (const [di, dj] of directions) {
                        const ni = i - di;
                        const nj = j - dj;
                        if (ni >= 0 && nj >= 0) {
                            const cost = dp[ni][nj].even + (i + 1) * (j + 1);
                            if (cost < newDp[i][j].odd) {
                                newDp[i][j].odd = cost;
                            }
                        }
                    }
                } else {
                    // Must wait, previous step was odd (moved)
                    const cost = dp[i][j].odd + waitCost[i][j];
                    if (cost < newDp[i][j].even) {
                        newDp[i][j].even = cost;
                    }
                }
                // Carry forward previous values if better
                if (dp[i][j].odd < newDp[i][j].odd) {
                    newDp[i][j].odd = dp[i][j].odd;
                }
                if (dp[i][j].even < newDp[i][j].even) {
                    newDp[i][j].even = dp[i][j].even;
                }
            }
        }

        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                dp[i][j] = newDp[i][j];
            }
        }
    }

    return Math.min(dp[m - 1][n - 1].odd, dp[m - 1][n - 1].even);
}

