    int cols = (int) n;
    long[][][] dp = new long[rows][cols][2];
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            Arrays.fill(dp[i][j], Long.MAX_VALUE);
        }
    }
    dp[0][0][0] = (0 + 1) * (0 + 1); // Initial entry cost at step 1 (odd)

    int[][] directions = {{1, 0}, {0, 1}}; // Down and Right

    for (int step = 1; step <= 2 * rows * cols; step++) {
        boolean isOddStep = (step % 2 == 1);
        long[][][] newDp = new long[rows][cols][2];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                Arrays.fill(newDp[i][j], Long.MAX_VALUE);
            }
        }

        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (isOddStep) {
                    // Can move from adjacent cells (previous step was even, waited)
                    for (int[] dir : directions) {
                        int ni = i - dir[0];
                        int nj = j - dir[1];
                        if (ni >= 0 && nj >= 0 && dp[ni][nj][1] != Long.MAX_VALUE) {
                            long cost = dp[ni][nj][1] + (i + 1) * (j + 1);
                            if (cost < newDp[i][j][0]) {
                                newDp[i][j][0] = cost;
                            }
                        }
                    }
                } else {
                    // Must wait, previous step was odd (moved)
                    if (dp[i][j][0] != Long.MAX_VALUE) {
                        long cost = dp[i][j][0] + waitCost[i][j];
                        if (cost < newDp[i][j][1]) {
                            newDp[i][j][1] = cost;
                        }
                    }
                }
                // Carry forward previous values if better
                if (dp[i][j][0] < newDp[i][j][0]) {
                    newDp[i][j][0] = dp[i][j][0];
                }
                if (dp[i][j][1] < newDp[i][j][1]) {
                    newDp[i][j][1] = dp[i][j][1];
                }
            }
        }

        for (int i = 0; i < rows; i++) {
